<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Desktop Environment</title>
<style>
html,body{margin:0;height:100%;overflow:hidden;background:#1e1e1e;color:#ddd;font-family:sans-serif;}
#desktop{position:relative;width:100%;height:100%;background:#2c2c2c;background-size:cover;}
#taskbar{position:absolute;bottom:0;left:0;right:0;height:40px;background:#111;display:flex;align-items:center;padding:0 10px;box-sizing:border-box;}
#taskbar button{margin-right:10px;background:#333;color:#fff;border:none;padding:5px 10px;cursor:pointer;}
.window{position:absolute;top:50px;left:50px;width:400px;height:300px;background:#2b2b2b;border:1px solid #555;box-shadow:0 0 10px rgba(0,0,0,0.7);display:none;flex-direction:column;min-width:360px;min-height:240px;}
.window .title-bar{background:#444;padding:5px 10px;cursor:move;display:flex;justify-content:space-between;align-items:center;}
.window .title-bar .title{color:#fff;}
.window .title-bar .win-close{background:#c33;color:#fff;border:none;padding:0 5px;cursor:pointer;}
.window .content{flex:1;overflow:auto;padding:5px;box-sizing:border-box;color:#ddd;}
/* Files app */
#files-window .content{display:flex;flex-direction:column;}
#files-path{margin-bottom:5px;font-size:0.9em;}
#files-up{margin-bottom:5px;padding:3px 6px;background:#555;color:#fff;border:none;cursor:pointer;}
#files-list{flex:1;overflow:auto;border:1px solid #555;background:#1e1e1e;}
.fs-item{padding:2px 5px;cursor:pointer;}
.fs-item:hover{background:#333;}
/* Notepad app */
#notepad-window .content{display:flex;flex-direction:column;height:100%;}
#tabs{display:flex;background:#333;padding:2px;}
.tab{padding:5px 10px;background:#555;margin-right:2px;color:#fff;cursor:pointer;}
.tab.active{background:#777;}
#new-tab{padding:5px 10px;background:#555;color:#fff;border:none;cursor:pointer;}
#editor{flex:1;width:100%;border:none;background:#1e1e1e;color:#ddd;padding:5px;box-sizing:border-box;resize:none;font-family:monospace;font-size:1em;}
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files">Files</button>
    <button id="open-notepad">Notepad</button>
  </div>

  <div id="files-window" class="window">
    <div class="title-bar"><span class="title">Files</span><button class="win-close">X</button></div>
    <div class="content">
      <div id="files-path">/</div>
      <button id="files-up">Up</button>
      <div id="files-list"></div>
    </div>
  </div>

  <div id="notepad-window" class="window">
    <div class="title-bar"><span class="title">Notepad</span><button class="win-close">X</button></div>
    <div class="content">
      <div id="tabs"><button id="new-tab">+</button></div>
      <textarea id="editor"></textarea>
    </div>
  </div>
</div>

<script>
(() => {
  const filesWin = document.getElementById('files-window');
  const notepadWin = document.getElementById('notepad-window');

  // Show / hide windows
  const showWin = win => { win.style.display = 'flex'; bringToFront(win); };
  const hideWin = win => { win.style.display = 'none'; };
  // Z‑index handling
  let z = 1;
  const bringToFront = win => { win.style.zIndex = ++z; };

  document.getElementById('open-files').addEventListener('click', () => showWin(filesWin));
  document.getElementById('open-notepad').addEventListener('click', () => showWin(notepadWin));
  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', e => hideWin(e.target.closest('.window')));
  });

  // Simple drag for windows
  document.querySelectorAll('.window .title-bar').forEach(bar => {
    bar.addEventListener('mousedown', e => {
      const win = bar.parentElement;
      bringToFront(win);
      const rect = win.getBoundingClientRect();
      const offsetX = e.clientX - rect.left;
      const offsetY = e.clientY - rect.top;
      const onMove = ev => {
        win.style.left = (ev.clientX - offsetX) + 'px';
        win.style.top = (ev.clientY - offsetY) + 'px';
      };
      const onUp = () => {
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
      };
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
    });
  });

  // ---------- Files app ----------
  const fsData = {
    '/': {type:'dir', children:{
      'bin': {type:'dir', children:{}},
      'etc': {type:'dir', children:{}},
      'home': {type:'dir', children:{
        'user': {type:'dir', children:{
          'Documents': {type:'dir', children:{}},
          'Downloads': {type:'dir', children:{}},
          'Pictures': {type:'dir', children:{}}
        }}
      }},
      'usr': {type:'dir', children:{}},
      'var': {type:'dir', children:{}}
    }}
  };
  let currentPath = '/';
  const pathEl = document.getElementById('files-path');
  const listEl = document.getElementById('files-list');
  const upBtn = document.getElementById('files-up');

  const getNode = path => {
    const parts = path.split('/').filter(p=>p);
    let node = fsData['/'];
    for (const part of parts) {
      if (node && node.children && node.children[part]) node = node.children[part];
      else return null;
    }
    return node;
  };

  const renderList = () => {
    pathEl.textContent = currentPath;
    listEl.innerHTML = '';
    const node = getNode(currentPath);
    if (!node) return;
    const entries = Object.entries(node.children).sort((a,b)=>a[0].localeCompare(b[0]));
    for (const [name, child] of entries) {
      const div = document.createElement('div');
      div.className = 'fs-item';
      div.textContent = name + (child.type==='dir' ? '/' : '');
      div.dataset.name = name;
      div.dataset.type = child.type;
      listEl.appendChild(div);
    }
  };

  // Double‑click navigation
  let clickTimer = null;
  listEl.addEventListener('click', e => {
    const item = e.target.closest('.fs-item');
    if (!item) return;
    if (clickTimer) {
      clearTimeout(clickTimer);
      clickTimer = null;
      if (item.dataset.type === 'dir') {
        const name = item.dataset.name;
        currentPath = (currentPath.endsWith('/') ? currentPath : currentPath + '/') + name;
        renderList();
      }
    } else {
      clickTimer = setTimeout(() => {
        clearTimeout(clickTimer);
        clickTimer = null;
      }, 300);
    }
  });

  upBtn.addEventListener('click', () => {
    if (currentPath === '/') return;
    const parts = currentPath.split('/').filter(p=>p);
    parts.pop();
    currentPath = '/' + parts.join('/');
    if (currentPath === '/') currentPath = '/';
    renderList();
  });

  renderList();

  // ---------- Notepad app ----------
  const tabsContainer = document.getElementById('tabs');
  const newTabBtn = document.getElementById('new-tab');
  const editor = document.getElementById('editor');

  let tabs = []; // {id, title, content}
  let activeTabId = null;

  const save = () => {
    localStorage.setItem('notepadTabs', JSON.stringify(tabs));
    localStorage.setItem('notepadActive', activeTabId);
  };
  const load = () => {
    const stored = localStorage.getItem('notepadTabs');
    if (stored) tabs = JSON.parse(stored);
    const act = localStorage.getItem('notepadActive');
    if (act && tabs.find(t=>t.id===act)) activeTabId = act;
    else if (tabs.length) activeTabId = tabs[0].id;
  };

  const createTab = (title='Untitled', content='') => {
    const id = 'tab-' + Date.now() + '-' + Math.random().toString(36).substr(2,5);
    tabs.push({id, title, content});
    activeTabId = id;
    renderTabs();
    updateEditor();
    save();
  };

  const renderTabs = () => {
    // keep the new‑tab button, rebuild others
    tabsContainer.innerHTML = '';
    tabs.forEach(t => {
      const el = document.createElement('div');
      el.className = 'tab' + (t.id===activeTabId ? ' active' : '');
      el.textContent = t.title;
      el.dataset.id = t.id;
      tabsContainer.appendChild(el);
    });
    tabsContainer.appendChild(newTabBtn);
  };

  const updateEditor = () => {
    const tab = tabs.find(t=>t.id===activeTabId);
    editor.value = tab ? tab.content : '';
  };

  tabsContainer.addEventListener('click', e => {
    const tabEl = e.target.closest('.tab');
    if (!tabEl) return;
    const id = tabEl.dataset.id;
    if (id) {
      activeTabId = id;
      renderTabs();
      updateEditor();
      save();
    }
  });

  newTabBtn.addEventListener('click', () => createTab());

  editor.addEventListener('input', () => {
    const tab = tabs.find(t=>t.id===activeTabId);
    if (tab) {
      tab.content = editor.value;
      save();
    }
  });

  load();
  if (tabs.length===0) createTab();
  else {
    renderTabs();
    updateEditor();
  }
})();
</script>
</body>
</html>
